#include <iostream>
#include <cstdint>

int main() {
    // هذه الأحجام شائعة لكنها ليست مضمونة من المعيار!
    std::cout << "char: " << sizeof(char) << " byte\n";    // دائمًا 1
    std::cout << "short: " << sizeof(short) << " bytes\n";   // غالبًا 2
    std::cout << "int: " << sizeof(int) << " bytes\n";       // غالبًا 4
    std::cout << "long: " << sizeof(long) << " bytes\n";      // 4 أو 8 حسب المنصة!
    std::cout << "long long: " << sizeof(long long) << " bytes\n"; // غالبًا 8
    std::cout << "float: " << sizeof(float) << " bytes\n";   // غالبًا 4
    std::cout << "double: " << sizeof(double) << " bytes\n"; // غالبًا 8
    std::cout << "pointer: " << sizeof(void*) << " bytes\n"; // 4 أو 8 حسب 32/64-bit

    // للأحجام الدقيقة: استخدم <cstdint>
    static_assert(sizeof(int8_t) == 1);
    static_assert(sizeof(int32_t) == 4);
    static_assert(sizeof(int64_t) == 8);
    return 0;
}

