#include <iostream>
#include <string>

int main() {
    const std::string name = "hello";

    // ❌ auto يُسقط const وينسخ القيمة
    auto a = name; // a هو std::string (نسخة مستقلة، ليست const)
    a = "changed"; // مسموح — لأن a ليست const!

    // ❌ auto يُسقط المرجع أيضًا
    std::string& ref = const_cast<std::string&>(name);
    auto b = ref; // b هي نسخة، ليست مرجعًا

    // ✅ const auto& يحافظ على const ويمنع النسخ
    const auto& c = name; // c هو const std::string& — لا نسخ، لا تعديل
    // c = "changed"; // خطأ — const!

    // ✅ auto& يحافظ على المرجع لكن يتطلب أن الأصل ليس const
    auto& d = const_cast<std::string&>(name); // d هو std::string&
    d = "modified"; // يُعدّل name!

    return 0;
}

#include <iostream>
#include <type_traits>

int main() {
    int x = 42;
    const int& cref = x;

    // auto يُسقط المرجع وconst
    auto a = cref; // a هو int (نسخة، لا مرجع، لا const)
    static_assert(std::is_same_v<decltype(a), int>);

    // decltype يحافظ على النوع الدقيق
    decltype(cref) b = x; // b هو const int& — نفس نوع cref بالضبط
    static_assert(std::is_same_v<decltype(b), const int&>);

    // decltype مع أقواس يُرجع مرجعًا دائمًا
    decltype((x)) c = x; // c هو int& — الأقواس تُغيّر النتيجة!
    static_assert(std::is_same_v<decltype((x)), int&>);

    // decltype(x) بدون أقواس يُرجع النوع كما هو
    static_assert(std::is_same_v<decltype(x), int>);

    return 0;
}

