#include <iostream>

void process(int value) {
    std::cout << "int: " << value << '\n';
}

void process(int* ptr) {
    if (ptr) std::cout << "pointer: " << *ptr << '\n';
    else std::cout << "null pointer\n";
}

int main() {
    // 0 هو int — يُستدعى النسخة int دائمًا!
    process(0);          // يطبع "int: 0" — ليس ما تريد مع المؤشرات

    // NULL قد يكون 0 أو ((void*)0) — سلوك غير مضمون مع التحميل الزائد
    process(NULL);       // قد يُستدعى int أو pointer حسب التعريف

    // nullptr له نوعه الخاص nullptr_t — لا يُخلط مع int
    process(nullptr);    // دائمًا يُستدعى النسخة int* — هذا ما تريده

    return 0;
}

#include <iostream>
#include <string>
#include <utility>

// lvalue reference: يرتبط بكائن له اسم وعنوان في الذاكرة
void readOnly(const std::string& s) {
    // s مرجع لـ const — لا نسخ، لا تعديل
    std::cout << "قراءة: " << s << '\n';
}

// rvalue reference: يرتبط بقيمة مؤقتة (مثل نتيجة دالة أو حرفي)
void takeOwnership(std::string&& s) {
    // s مرجع لقيمة مؤقتة — يمكن 'سرقة' محتواها
    std::string owned = std::move(s); // نقل لا نسخ
    std::cout << "ملكية: " << owned << '\n';
}

int main() {
    std::string data = "hello world";

    // data هي lvalue — تُمرر لـ const std::string&
    readOnly(data);
    readOnly("temporary"); // النص الحرفي مؤقت — يُقبل أيضًا

    // std::move(data) تُحوّل data لـ rvalue reference
    takeOwnership(std::move(data));
    // بعد النقل: data قد تكون فارغة أو في حالة غير محددة
    // لا تستخدم data بعد move!

    return 0;
}

#include <iostream>

// ❌ enum عادي: الأسماء تُلوّث النطاق المحيط
