#include <iostream>

struct Base { virtual ~Base() = default; int x = 1; };
struct Derived : Base { int y = 2; };

int main() {
    // 1. static_cast: تحويلات آمنة ومعروفة وقت الترجمة
    double d = 3.7;
    int n = static_cast<int>(d); // 3 — يقطع الكسر، واضح ومقصود
    Base* b = static_cast<Base*>(new Derived()); // تحويل لأعلى في الوراثة — آمن

    // 2. dynamic_cast: تحويل بين أنواع في وراثة polymorphic
    Base* base = new Derived();
    Derived* derived = dynamic_cast<Derived*>(base); // آمن — يفحص وقت التشغيل
    if (derived) {
        // التحويل نجح — يمكن الوصول لـ y
    }
    Base* wrong = new Base();
    Derived* fail = dynamic_cast<Derived*>(wrong); // يُرجع nullptr — التحويل فشل

    // 3. reinterpret_cast: إعادة تفسير البايتات — خطير جدًا!
    int value = 42;
    char* bytes = reinterpret_cast<char*>(&value);
    // bytes تُفسّر ذاكرة value كـ char — مفيد لمعالجة البايتات
    // لكن لا تستخدمه للتحويلات العادية!

    // 4. const_cast: إزالة أو إضافة const — خطير إذا أزلت const من كائن فعليًا
    const int& cref = value;
    int& mutable_ref = const_cast<int&>(cref);
    mutable_ref = 99; // يعمل هنا لأن value الأصلي ليس const
    // لكن لو كان cref يشير لكائن const فعليًا — سلوك غير معرّف!

    delete base;
    delete wrong;
    return 0;
}

#include <iostream>
