int main() {
    // تحويل ضمني من double لـ int — يقطع الكسر صامتًا!
    double pi = 3.14159;
    int approx = pi; // 3 — المُصرِّف قد يُحذّر لكنه يسمح

    // تحويل ضمني من أكبر لـ أصغر — قد يفقد بيانات!
    int32_t big = 3000000000; // أكبر من INT32_MAX (2147483647)
    // int16_t small = big; // خطأ — قد يحذّر لكنه يسمح في بعض الأماكن

    // تحويل ضمني من unsigned لـ signed — سلوك معرّف لكن قد يُفاجئ
    uint32_t u = 4000000000u;
    int32_t s = u; // قيمة سالبة! لأن البت الأعلى هو 1
    // s = -294967296 — ليس 4000000000!

    // ✅ استخدم static_cast صريحًا لإظهار النية
    int explicit_approx = static_cast<int>(pi); // واضح: أنا أعرف أنني أقطع الكسر

    // ✅ مع المُصرِّف الحديث: استخدم -Wconversion لرؤية كل التحويلات الضمنية
    return s < 0 ? 1 : 0;
}

#include <iostream>
#include <type_traits>

// النمط القديم: نوع الإرجاع قبل اسم الدالة
// مشكلة: لا يمكن استخدام المُعاملات في نوع الإرجاع
// template<typename A, typename B>
// ??? add(A a, B b) { return a + b; } // ما نوع الإرجاع؟

// النمط الحديث: trailing return type مع auto وdecltype
template<typename A, typename B>
auto add(A a, B b) -> decltype(a + b) {
    return a + b;
} // نوع الإرجاع = decltype(a + b) — يُحدد تلقائيًا

// في C++14: auto يكفي (المُصرِّف يستنتج نوع الإرجاع)
template<typename A, typename B>
auto multiply(A a, B b) {
    return a * b;
}

int main() {
    auto x = add(3, 4);       // int
    auto y = add(3.5, 2);     // double
    auto z = multiply(3, 2.5); // double
    return static_cast<int>(x + y + z); // 12
}

