// const في نهاية دالة عضو: الدالة لا تُعدّل أعضاء الكائن
struct Rectangle {
    float width, height;

    float area() const { // const يعني: هذه الدالة لا تُغيّر width أو height
        return width * height;
    }

    void scale(float factor) { // بدون const — لأنها تُعدّل الأعضاء
        width *= factor;
        height *= factor;
    }
};

int main() {
    // const كائن: لا يمكن استدعاء دوال غير const عليه
    const Rectangle r{10.0f, 5.0f};
    float a = r.area(); // ✅ — area() const
    // r.scale(2.0f); // ❌ — scale() ليست const

    // مرجع const في حلقة: لا نسخ + لا تعديل
    const std::vector<int> data = {1, 2, 3, 4, 5};
    for (const auto& item : data) { // const auto& — أفضل ممارسة
        // item = 99; // خطأ — const
    }

    return static_cast<int>(a);
}

